String lastSubstring(String s) {
    int n = s.length();
    StringBuilder result = new StringBuilder();
    for (int i = n - 1; i >= 0; i--) {
        StringBuilder temp = new StringBuilder();
        for (int j = i + 1; j < n; j++) {
            temp.append(s.charAt(j));
        }
        result.append(temp.reverse().toString());
    }
    return result.reverse().toString();
}

